using Portal.BuildingBlocks;using Portal.Notification.Application;using Portal.Notification.Contracts;
namespace Portal.Notification.Api;
public static class NotificationEndpoints
{
 public static IEndpointRouteBuilder MapNotificationEndpoints(this IEndpointRouteBuilder e){var g=e.MapGroup("/api/notifications").RequireAuthorization();g.MapPost("/templates",async(CreateTemplateRequest r,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.CreateTemplateAsync(r,h.TraceIdentifier,c),201)).RequireAuthorization(PortalPermissions.NotificationManage);g.MapPut("/templates/{id:guid}",async(Guid id,UpdateTemplateRequest r,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.UpdateTemplateAsync(id,r,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.NotificationManage);g.MapPost("/templates/{id:guid}/activate",async(Guid id,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.SetTemplateActiveAsync(id,true,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.NotificationManage);g.MapPost("/templates/{id:guid}/deactivate",async(Guid id,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.SetTemplateActiveAsync(id,false,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.NotificationManage);g.MapGet("/templates",async(NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.GetTemplatesAsync(c))).RequireAuthorization(PortalPermissions.NotificationRead);
 g.MapPost("/send",async(SendNotificationRequest r,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.SendAsync(r,h.TraceIdentifier,c),202)).RequireAuthorization(PortalPermissions.NotificationSend);g.MapPost("/schedule",async(ScheduleNotificationRequest r,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.ScheduleAsync(r,h.TraceIdentifier,c),202)).RequireAuthorization(PortalPermissions.NotificationSend);g.MapGet("/{id:guid}",async(Guid id,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.GetStatusAsync(id,c))).RequireAuthorization(PortalPermissions.NotificationRead);g.MapGet("/",async(NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.GetMessagesAsync(c))).RequireAuthorization(PortalPermissions.NotificationRead);g.MapPost("/{id:guid}/retry",async(Guid id,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.RetryAsync(id,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.NotificationManage);g.MapPost("/{id:guid}/cancel",async(Guid id,NotificationService s,HttpContext h,CancellationToken c)=>Reply(h,await s.CancelAsync(id,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.NotificationManage);return e;}
 static IResult Reply<T>(HttpContext h,Result<T> r,int status=200){if(r.IsSuccess)return Results.Json(new ApiResponse<T>(r.Value,null,h.TraceIdentifier),statusCode:status);var code=r.Error!.Code.EndsWith("not_found")?404:r.Error.Code.EndsWith("conflict")?409:400;return Results.Json(new ApiResponse<T>(default,r.Error,h.TraceIdentifier),statusCode:code);}
}
